import{_ as n,o as s,c as a,f as p}from"./app.cc8f21a4.js";const b=JSON.parse('{"title":"Linux \u5B89\u88C5 Python3","description":"","frontmatter":{"title":"Linux \u5B89\u88C5 Python3","date":"2022-02-19T00:00:00.000Z","categories":["\u540E\u7AEF"],"tags":["Linux"],"meta":[{"name":"description","content":"Linux \u5B89\u88C5 python3"},{"name":"keywords","content":"LINUX,linux,python,python3"}]},"headers":[{"level":2,"title":"1. \u4F9D\u8D56\u5B89\u88C5","slug":"_1-\u4F9D\u8D56\u5B89\u88C5","link":"#_1-\u4F9D\u8D56\u5B89\u88C5","children":[]},{"level":2,"title":"2. python3 \u4E0B\u8F7D","slug":"_2-python3-\u4E0B\u8F7D","link":"#_2-python3-\u4E0B\u8F7D","children":[]},{"level":2,"title":"3. python3 \u7F16\u8BD1\u5B89\u88C5","slug":"_3-python3-\u7F16\u8BD1\u5B89\u88C5","link":"#_3-python3-\u7F16\u8BD1\u5B89\u88C5","children":[]},{"level":2,"title":"4. \u521B\u5EFA\u8F6F\u8FDE\u63A5","slug":"_4-\u521B\u5EFA\u8F6F\u8FDE\u63A5","link":"#_4-\u521B\u5EFA\u8F6F\u8FDE\u63A5","children":[]},{"level":2,"title":"5. \u4FEE\u6539 yum \u914D\u7F6E","slug":"_5-\u4FEE\u6539-yum-\u914D\u7F6E","link":"#_5-\u4FEE\u6539-yum-\u914D\u7F6E","children":[]}],"relativePath":"contents/Backend/Linux/linux\u5B89\u88C5python3.md"}'),l={name:"contents/Backend/Linux/linux\u5B89\u88C5python3.md"},e=p(`<blockquote><p>\u672C\u6587\u4ECB\u7ECD Linux \u73AF\u5883\u4E0B\u5B89\u88C5 python3 \u4EE5\u53CA\u4E00\u4E9B\u9700\u8981\u6CE8\u610F\u70B9\u3002</p></blockquote><h2 id="_1-\u4F9D\u8D56\u5B89\u88C5" tabindex="-1">1. \u4F9D\u8D56\u5B89\u88C5 <a class="header-anchor" href="#_1-\u4F9D\u8D56\u5B89\u88C5" aria-hidden="true">#</a></h2><p>gcc \u662F\u4E00\u4E2A\u7528\u4E8E linux \u7CFB\u7EDF\u4E0B\u7F16\u7A0B\u7684\u7F16\u8BD1\u5668\uFF0C\u7531\u4E8E python3 \u9700\u8981\u7F16\u8BD1\u5B89\u88C5\uFF0C\u56E0\u6B64\uFF0C\u9700\u8981\u9996\u5148\u5B89\u88C5 gcc\u3002\u5148\u67E5\u770B\u4E00\u4E0B\u7CFB\u7EDF\u4E2D\uFF0C\u662F\u5426\u5B89\u88C5\u4E86 gcc\u3002</p><div class="language-sh"><button class="copy"></button><span class="lang">sh</span><pre><code><span class="line"><span style="color:#A6ACCD;">gcc --versions</span></span>
<span class="line"></span></code></pre></div><p>\u53D1\u73B0\u6CA1\u6709\u5B89\u88C5\uFF0C\u5219\u9700\u8981\u5B89\u88C5\u3002\u53C2\u6570-y \u7684\u4F5C\u7528\u662F\u5728\u5B89\u88C5\u8FC7\u7A0B\u4E2D\u81EA\u52A8\u786E\u8BA4\u3002</p><div class="language-sh"><button class="copy"></button><span class="lang">sh</span><pre><code><span class="line"><span style="color:#A6ACCD;">yum -y install gcc</span></span>
<span class="line"></span></code></pre></div><p>\u7F16\u8BD1\u5B89\u88C5 python3 \u8FC7\u7A0B\u4E2D\uFF0C\u6839\u636E\u7CFB\u7EDF\u672C\u8EAB\u7684\u4F9D\u8D56\uFF0C\u53EF\u80FD\u51FA\u73B0\u7684\u4E0D\u540C\u7684\u62A5\u9519\u4FE1\u606F\u3002\u63D0\u524D\u6309\u7167\u597D\u4F9D\u8D56\u5305\u3002</p><div class="language-sh"><button class="copy"></button><span class="lang">sh</span><pre><code><span class="line"><span style="color:#A6ACCD;">yum -y install zlib</span><span style="color:#89DDFF;">*</span></span>
<span class="line"><span style="color:#A6ACCD;">yum -y install libffi-devel</span></span>
<span class="line"><span style="color:#A6ACCD;">yum -y install openssl-devel</span></span>
<span class="line"></span></code></pre></div><h2 id="_2-python3-\u4E0B\u8F7D" tabindex="-1">2. python3 \u4E0B\u8F7D <a class="header-anchor" href="#_2-python3-\u4E0B\u8F7D" aria-hidden="true">#</a></h2><p>\u5728\u4E0B\u8F7D\u524D\u53EF\u4EE5\u68C0\u67E5\u4E00\u4E0B\u670D\u52A1\u5668\u4E2D python \u7684\u7248\u672C\uFF0C\u4E00\u822C linux \u670D\u52A1\u5668\u4F1A\u81EA\u5E26 python2\u3002\u4EE5\u4E0B\u6240\u6709\u64CD\u4F5C\u90FD\u662F\u5728 root \u8D26\u6237\u4E2D\u8FDB\u884C\u3002</p><p>python --version \u5F53\u670D\u52A1\u5668\u7F51\u7EDC\u8F83\u597D\u65F6\uFF0C\u53EF\u4EE5\u76F4\u63A5\u4F7F\u7528\u4EE5\u4E0B\u547D\u4EE4\u4E0B\u8F7D python3 \u7684\u538B\u7F29\u5305\u3002\u4E0B\u8F7D\u7684\u7248\u672C\u4E3A python3.7\uFF0C\u4E0B\u8F7D\u5230\u670D\u52A1\u5668\u4E3B\u76EE\u5F55\u4E2D\uFF08\u4F4D\u7F6E\u53EF\u81EA\u5B9A\u4E49\uFF09\u3002</p><div class="language-sh"><button class="copy"></button><span class="lang">sh</span><pre><code><span class="line"><span style="color:#82AAFF;">cd</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">~</span></span>
<span class="line"><span style="color:#A6ACCD;">wget https://www.python.org/ftp/python/3.7.0/Python-3.7.0.tgz</span></span>
<span class="line"></span></code></pre></div><p>\u5F53\u670D\u52A1\u5668\u7F51\u7EDC\u4E0D\u597D\u65F6\uFF0C\u547D\u4EE4\u4E0B\u8F7D\u82B1\u8D39\u65F6\u95F4\u8F83\u957F\uFF0C\u53EF\u4EE5\u8003\u8651\u5728\u5176\u4ED6\u673A\u5668\u4E0A\u5148\u4E0B\u597D\u538B\u7F29\u5305\uFF0C\u7136\u540E\u901A\u8FC7\u5DE5\u5177\uFF08MobaXterm,Xshell,...\uFF09\u4E0A\u4F20\u5230\u670D\u52A1\u5668\u3002</p><h2 id="_3-python3-\u7F16\u8BD1\u5B89\u88C5" tabindex="-1">3. python3 \u7F16\u8BD1\u5B89\u88C5 <a class="header-anchor" href="#_3-python3-\u7F16\u8BD1\u5B89\u88C5" aria-hidden="true">#</a></h2><p>\u89E3\u538B\u4E0B\u8F7D\u7684 python3 \u538B\u7F29\u5305\u3002</p><div class="language-sh"><button class="copy"></button><span class="lang">sh</span><pre><code><span class="line"><span style="color:#A6ACCD;">tar -zxvf Python-3.7.0.tgz</span></span>
<span class="line"></span></code></pre></div><p>\u89E3\u538B\u540E\u4E3B\u76EE\u5F55\u4E0B\u4F1A\u591A\u51FA\u4E00\u4E2A Python-3.7.0 \u6587\u4EF6\u5939\u3002</p><p>\u65B0\u5EFA\u4E00\u4E2A python3 \u7684\u5B89\u88C5\u76EE\u5F55(\u4F4D\u7F6E\u53EF\u81EA\u5B9A\u4E49)\u3002</p><div class="language-sh"><button class="copy"></button><span class="lang">sh</span><pre><code><span class="line"><span style="color:#A6ACCD;">mkdir /usr/lib/python3.7</span></span>
<span class="line"></span></code></pre></div><p>\u8FDB\u5165 Python-3.7.0 \u76EE\u5F55\u4E0B\uFF0C\u300C\u6307\u5B9A\u5B89\u88C5\u76EE\u5F55\uFF0C\u8BBE\u7F6E\u542F\u7528 ssl \u529F\u80FD\u300D\u3002</p><div class="language-sh"><button class="copy"></button><span class="lang">sh</span><pre><code><span class="line"><span style="color:#82AAFF;">cd</span><span style="color:#A6ACCD;"> Python-3.7.0</span></span>
<span class="line"><span style="color:#A6ACCD;">./configure --prefix=/usr/lib/python3.7 --with-ssl</span></span>
<span class="line"></span></code></pre></div><p>\u7F16\u8BD1\u5B89\u88C5\u3002</p><div class="language-sh"><button class="copy"></button><span class="lang">sh</span><pre><code><span class="line"><span style="color:#A6ACCD;">make </span><span style="color:#89DDFF;">&amp;&amp;</span><span style="color:#A6ACCD;"> make install</span></span>
<span class="line"></span></code></pre></div><h2 id="_4-\u521B\u5EFA\u8F6F\u8FDE\u63A5" tabindex="-1">4. \u521B\u5EFA\u8F6F\u8FDE\u63A5 <a class="header-anchor" href="#_4-\u521B\u5EFA\u8F6F\u8FDE\u63A5" aria-hidden="true">#</a></h2><p>\u4E0A\u8FF0\u6B65\u9AA4\u5B8C\u6210\u540E\uFF0C\u5176\u5B9E python3 \u5DF2\u7ECF\u5B89\u88C5\u5B8C\u6BD5\uFF0C\u4F46\u662F\u4E3A\u4E86\u65B9\u4FBF\u4F7F\u7528\uFF0C\u4E00\u822C\u4F1A\u521B\u5EFA python3 \u548C pip3 \u7684\u8F6F\u8FDE\u63A5\u3002\u521B\u5EFA\u540E\u53EF\u76F4\u63A5\u5728\u7EC8\u7AEF\u901A\u8FC7 python \u547D\u4EE4\u8FDB\u5165 python \u548C pip3 \u547D\u4EE4\u5B89\u88C5 python \u5305\u3002</p><p>\u521B\u5EFA python3 \u548C pip3 \u8F6F\u8FDE\u63A5\uFF1A</p><div class="language-sh"><button class="copy"></button><span class="lang">sh</span><pre><code><span class="line"><span style="color:#A6ACCD;">ln -s /usr/lib/python3.7/bin/python3.7 /usr/bin/python3</span></span>
<span class="line"><span style="color:#A6ACCD;">ln -s /usr/lib/python3.7/bin/pip3.7 /usr/bin/pip3</span></span>
<span class="line"><span style="color:#A6ACCD;">ln -s /usr/bin/pip3 /usr/bin/pip</span></span>
<span class="line"></span></code></pre></div><p>\u7CFB\u7EDF\u9ED8\u8BA4\u7684 python \u8F6F\u8FDE\u63A5\u6307\u5411\u7684\u662F python2\uFF0C\u5982\u679C\u6211\u4EEC\u9700\u8981\u66F4\u65B9\u4FBF\u4F7F\u7528\uFF0C\u53EF\u4EE5\u5220\u9664\u539F\u6709\u7684 python \u8F6F\u8FDE\u63A5\uFF0C\u5E76\u5EFA\u7ACB\u65B0\u7684 python \u8F6F\u8FDE\u63A5\u6307\u5411 python3\u3002</p><div class="language-sh"><button class="copy"></button><span class="lang">sh</span><pre><code><span class="line"><span style="color:#A6ACCD;">rm -f /usr/bin/python</span></span>
<span class="line"><span style="color:#A6ACCD;">ln -s /usr/bin/python3 /usr/bin/python</span></span>
<span class="line"></span></code></pre></div><p>\u67E5\u770B\u6700\u65B0\u7684\u6709 python \u7684\u8F6F\u8FDE\u63A5\u3002</p><div class="language-sh"><button class="copy"></button><span class="lang">sh</span><pre><code><span class="line"><span style="color:#A6ACCD;">ll /usr/bin/ </span><span style="color:#89DDFF;">|</span><span style="color:#A6ACCD;">grep python</span></span>
<span class="line"></span></code></pre></div><p>\u67E5\u770B python \u7248\u672C\u3002\u663E\u793A\u4E3A python 3.7.0\u3002</p><div class="language-sh"><button class="copy"></button><span class="lang">sh</span><pre><code><span class="line"><span style="color:#A6ACCD;">python --version</span></span>
<span class="line"></span></code></pre></div><h2 id="_5-\u4FEE\u6539-yum-\u914D\u7F6E" tabindex="-1">5. \u4FEE\u6539 yum \u914D\u7F6E <a class="header-anchor" href="#_5-\u4FEE\u6539-yum-\u914D\u7F6E" aria-hidden="true">#</a></h2><p>Linux centos7 \u81EA\u5E26\u7684 python \u7248\u672C\u662F 2.7\uFF0Cyum \u4F7F\u7528 python2.7 \u4F5C\u4E3A\u547D\u4EE4\u89E3\u91CA\u5668\u3002\u5B89\u88C5 python3 \u540E\uFF0C\u8F6F\u8FDE\u63A5/usr/bin/python \u6307\u5411\u7684\u7248\u672C\u662F python3\uFF0C\u4E0D\u4FEE\u6539 yum \u7684\u914D\u7F6E\uFF0C\u4F1A\u5BFC\u81F4 yum \u4F7F\u7528\u62A5\u9519\uFF0C\u65E0\u6CD5\u5B89\u88C5\u5305\u7B49\u3002</p><p>\u300C\u62A5\u9519\u4FE1\u606F 1\uFF1A\u300D</p><blockquote><p>File &quot;/usr/bin/yum&quot;, line 30 except KeyboardInterrupt, e: ^ SyntaxError: invalid syntax</p></blockquote><p>\u300C\u62A5\u9519\u4FE1\u606F 2\uFF1A\u300D</p><blockquote><p>Downloading packages: File &quot;/usr/libexec/urlgrabber-ext-down&quot;, line 28 except OSError, e: ^ SyntaxError: invalid syntax</p></blockquote><p>\u300C\u89E3\u51B3\u529E\u6CD5\uFF1A\u300D</p><p>\u4FEE\u6539 yum \u914D\u7F6E\u6587\u4EF6\uFF0C\u4E0B\u9762\u4E24\u4E2A\u6587\u4EF6\u90FD\u8981\u4FEE\u6539\u3002</p><p><code>vi /usr/bin/yum</code><code>vi /usr/libexec/urlgrabber-ext-down</code></p><p>\u6309 i \u8FDB\u5165\u7F16\u8F91\u6A21\u5F0F\uFF0C\u5728\u7B2C\u4E00\u884C <code>#!/usr/bin/python</code> \u628A\u4FEE\u6539\u4E3A <code>#!/usr/bin/python2.7</code></p><p>\u6309 ESC \u9000\u51FA\u7F16\u8F91\u6A21\u5F0F\uFF0C<code>:wq</code> \u9000\u51FA\u4FDD\u5B58\u3002</p>`,44),o=[e];function t(c,i,r,h,y,d){return s(),a("div",null,o)}const g=n(l,[["render",t]]);export{b as __pageData,g as default};
